def triples_sum_to_zero(l: list):
    n = len(l)
    for i in range(n-2):
        seen = set()
        for j in range(i+1, n):
            complement = - (l[i] + l[j])
            if complement in seen:
                return True
            seen.add(l[j])
    return False

def pairs_sum_to_zero(l):
