def decimal_to_binary(decimal):
    if decimal == 0:
        return "db0db"

    binary = ""
    while decimal > 0:
        remainder = decimal % 2
        binary = str(remainder) + binary
        decimal = decimal // 2

    return "db" + binary + "db"

