def starts_one_ends(n):
    if n == 1:
        return 1  # Only '1' itself starts and ends with 1
    else:
        # For n > 1, calculate the count
        # There are 9 options for the first digit (2-9) and 10^(n-2) options for the middle digits
        # There are 10 options for the last digit (0-9)
        # However, we need to subtract the count of numbers that both start and end with 1
        # which is 10^(n-2) (since the middle digits can be anything)
        return 2 * 9 * 10**(n-2) - 10**(n-2)

def get_row(lst, x):
