    return result

def sort_array(array):
    if not array:
        return []

    # Calculate the sum of the first and last elements
    sum_first_last = array[0] + array[-1]

    # Determine the sorting order based on the sum
    if sum_first_last % 2 == 0:
        # Sort in descending order
        sorted_array = sorted(array, reverse=True)
    else:
        # Sort in ascending order
        sorted_array = sorted(array)

    return sorted_array

def encode(message):
    def shift_vowel(vowel):
        vowels = "aeiouAEIOU"
        index = vowels.index(vowel)
        return vowels[(index + 2) % len(vowels)]

    encoded_message = []
    for char in message:
        if char.isalpha():
            if char.islower():
                new_char = char.upper()
            else:
                new_char = char.lower()
            if new_char in "aeiouAEIOU":
                new_char = shift_vowel(new_char)
            encoded_message.append(new_char)
        else:
            encoded_message.append(char)

    return ''.join(encoded_message)

