def histogram(test):
    if not test:
        return {}

    words = test.split()
    letter_count = {}

    for word in words:
        if word in letter_count:
            letter_count[word] += 1
        else:
            letter_count[word] = 1

    max_count = max(letter_count.values())
    result = {word: count for word, count in letter_count.items() if count == max_count}

    return result

