def intersection(interval1, interval2):
    start_max = max(interval1[0], interval2[0])
    end_min = min(interval1[1], interval2[1])

    if start_max > end_min:
        return "NO"

    intersection_length = end_min - start_max + 1

    def is_prime(n):
        if n <= 1:
            return False
        if n <= 3:
            return True
        if n % 2 == 0 or n % 3 == 0:
            return False
        i = 5
        while i * i <= n:
            if n % i == 0 or n % (i + 2) == 0:
                return False
            i += 6
        return True

    return "YES" if is_prime(intersection_length) else "NO"

def prod_signs(arr):
    if not arr:
        return None

    sign_product = 1
    magnitude_sum = 0

    for num in arr:
        if num == 0:
            return 0
        sign_product *= (1 if num > 0 else -1)
        magnitude_sum += abs(num)

    return magnitude_sum * sign_product

from typing import List

def minPath(grid: List[List[int]], k: int) -> List[int]:
    N = len(grid)
    directions = [(0, 1), (1, 0), (-1, 0), (0, -1)]  # right, down, up, left

    def dfs(x, y, path):
        nonlocal min_path
        if len(path) == k:
            if not min_path or path < min_path:
                min_path = path[:]
            return

        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < N and 0 <= ny < N:
                dfs(nx, ny, path + [grid[nx][ny]])

    min_path = None
    for i in range(N):
        for j in range(N):
            dfs(i, j, [grid[i][j]])

    return min_path

def tri(n):
    if n == 0:
        return [1]
    elif n == 1:
        return [1, 3]

    tribonacci = [1, 3]
    for i in range(2, n + 1):
        if i % 2 == 0:
            tribonacci.append(1 + i // 2)
        else:
            tribonacci.append(tribonacci[i - 1] + tribonacci[i - 2] + tribonacci[i + 1])

    return tribonacci

def digits(n):
    product = 1
    has_odd = False
    while n > 0:
        digit = n % 10
        if digit % 2 != 0:
            product *= digit
            has_odd = True
        n //= 10
    return product if has_odd else 0

