    stack = []
    nested = False

    for char in string:
        if char == '[':
            stack.append(char)
        elif char == ']' and stack:
            stack.pop()
            if stack:
                nested = True

    return nested and not stack

import math

def sum_squares(lst):
    return sum(math.ceil(x)**2 for x in lst)

def can_arrange(arr):
    for i in range(len(arr) - 1, 0, -1):
        if arr[i] < arr[i - 1]:
            return i
    return -1

def largest_smallest_integers(lst):
    negative = [x for x in lst if x < 0]
    positive = [x for x in lst if x > 0]

    largest_negative = max(negative) if negative else None
    smallest_positive = min(positive) if positive else None

    return (largest_negative, smallest_positive)

def compare_one(a, b):
    def convert_to_float(value):
        if isinstance(value, str):
            value = value.replace(',', '.')
            return float(value)
        return value

    a_float = convert_to_float(a)
    b_float = convert_to_float(b)

    if a_float > b_float:
        return a
    elif b_float > a_float:
        return b
    else:
        return None

def is_equal_to_sum_even(n):
    # The smallest sum of four positive even numbers is 2 + 2 + 2 + 2 = 8
    if n < 8:
        return False

    # If n is even and greater than or equal to 8, it can always be expressed as the sum of four even numbers
    return n % 2 == 0

import math

def special_factorial(n):
    result = 1
    for i in range(1, n + 1):
        result *= math.factorial(i)
    return result

def fix_spaces(text):
    result = []
    space_count = 0

    for char in text:
        if char == ' ':
            space_count += 1
        else:
            if space_count > 2:
                result.append('-')
            elif space_count > 0:
                result.extend(['_'] * space_count)
            result.append(char)
            space_count = 0

    # Handle trailing spaces
    if space_count > 2:
        result.append('-')
    elif space_count > 0:
        result.extend(['_'] * space_count)

    return ''.join(result)

def sum_squares(lst):
    total = 0
    for i, num in enumerate(lst):
        if i % 3 == 0:
            total += num ** 2
        elif i % 4 == 0:
            total += num ** 3
    return total

def words_in_sentence(sentence):
    def is_prime(n):
        if n <= 1:
            return False
        if n <= 3:
            return True
        if n % 2 == 0 or n % 3 == 0:
            return False
        i = 5
        while i * i <= n:
            if n % i == 0 or n % (i + 2) == 0:
                return False
            i += 6
        return True

    words = sentence.split()
    prime_length_words = [word for word in words if is_prime(len(word))]
    return ' '.join(prime_length_words)

from fractions import Fraction

def simplify(x, n):
    return Fraction(x) * Fraction(n).denominator == Fraction(x).numerator

def specialFilter(nums):
    def is_odd_digit(digit):
        return digit in {'1', '3', '5', '7', '9'}

    count = 0
    for num in nums:
        if num > 10:
            str_num = str(abs(num))
            if is_odd_digit(str_num[0]) and is_odd_digit(str_num[-1]):
                count += 1
    return count

def get_max_triples(n):
    # Calculate the values of a[i] for each i from 1 to n
    a = [i * i - i + 1 for i in range(1, n + 1)]

    # Count the number of valid triples (a[i], a[j], a[k])
    count = 0
    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                if (a[i] + a[j] + a[k]) % 3 == 0:
                    count += 1

    return count

def bf(planet1, planet2):
    planets = ["Mercury", "Venus", "Earth", "Mars", "Jupiter", "Saturn", "Uranus", "Neptune"]
    try:
        index1 = planets.index(planet1)
        index2 = planets.index(planet2)
    except ValueError:
        return ()

    if index1 > index2:
        index1, index2 = index2, index1

    return tuple(planets[index1 + 1:index2])

def x_or_y(n, x, y):
    if all(n % i != 0 for i in range(2, int(n**0.5) + 1)):
        return x
    else:
        return y

def even_odd_count(num):
    num = abs(num)  # Ensure the number is positive
    even_count = 0
    odd_count = 0

    while num > 0:
        digit = num % 10
        if digit % 2 == 0:
            even_count += 1
        else:
            odd_count += 1
        num //= 10

    return (even_count, odd_count)

import math

def right_angle_triangle(a, b, c):
    # Sort the sides to ensure the largest is considered as the hypotenuse
    sides = sorted([a, b, c])

    # Check the Pythagorean theorem: a^2 + b^2 = c^2
    return math.isclose(sides[0]**2 + sides[1]**2, sides[2]**2)

def find_max(words):
    max_word = ""
    max_unique_chars = 0

    for word in words:
        unique_chars = set(word)
        if len(unique_chars) > max_unique_chars or (len(unique_chars) == max_unique_chars and word < max_word):
            max_word = word
            max_unique_chars = len(unique_chars)

    return max_word

def eat(number, need, remaining):
    if need <= remaining:
        return [number + need, remaining - need]
    else:
        return [number + remaining, 0]

def do_algebra(operator, operand):
    expression = str(operand[0])
    for i in range(len(operator)):
        expression += f" {operator[i]} {operand[i+1]}"
    return eval(expression)

def solve(s):
    has_letters = any(c.isalpha() for c in s)
    if not has_letters:
        return s[::-1]

    result = []
    for char in s:
        if char.isalpha():
            result.append(char.swapcase())
        else:
            result.append(char)

    return ''.join(result)

import hashlib

def string_to_md5(text):
    if not text:
        return None
    return hashlib.md5(text.encode()).hexdigest()

def generate_integers(a, b):
    if a > b:
        a, b = b, a
    return [i for i in range(a, b + 1) if i % 2 == 0]
